problems.solutionCode:
package main

import "math"

func Solve(R [3][3]float64) bool {
    // 1. Check determinant
    det := R[0][0]*(R[1][1]*R[2][2] - R[1][2]*R[2][1]) - 
           R[0][1]*(R[1][0]*R[2][2] - R[1][2]*R[2][0]) + 
           R[0][2]*(R[1][0]*R[2][1] - R[1][1]*R[2][0])
    if math.Abs(det - 1.0) > 1e-5 {
        return false
    }

    // 2. Check R^T * R == I
    var RTR [3][3]float64
    for i := 0; i < 3; i++ {
        for j := 0; j < 3; j++ {
            sum := 0.0
            for k := 0; k < 3; k++ {
                sum += R[k][i] * R[k][j] // R[k][i] is R^T[i][k]
            }
            RTR[i][j] = sum
        }
    }

    for i := 0; i < 3; i++ {
        for j := 0; j < 3; j++ {
            expected := 0.0
            if i == j {
                expected = 1.0
            }
            if math.Abs(RTR[i][j] - expected) > 1e-5 {
                return false
            }
        }
    }

    return true
}

