package main

import "math"

func Solve(theta1, theta2, L1, L2 float64) [2]float64 {
    x := L1*math.Cos(theta1) + L2*math.Cos(theta1+theta2)
    y := L1*math.Sin(theta1) + L2*math.Sin(theta1+theta2)
    return [2]float64{x, y}
}

problems.testCode:
import "math"

func assertNear(got, want [2]float64) {
    if math.Abs(got[0]-want[0]) > 1e-5 || math.Abs(got[1]-want[1]) > 1e-5 {
        panic(nil) // Trigger failure
    }
}

func main() {
    // Home configuration: angles = 0
    assertNear(Solve(0, 0, 1.0, 1.0), [2]float64{2.0, 0.0})

    // 90 degree turn on joint 1
    assertNear(Solve(math.Pi/2, 0, 1.0, 1.0), [2]float64{0.0, 2.0})

    // Joint 1 = 90 deg, Joint 2 = -90 deg (folding back)
    assertNear(Solve(math.Pi/2, -math.Pi/2, 1.0, 1.0), [2]float64{1.0, 1.0})
}
